mapper.select:
SELECT FLOW.DOMAIN_ID as domainId,


        round(avgMerge(CPU_RATE_AVG),2) as avgCpuRate


        round(avgMerge(MEMORY_AVG),2) as avgMemRate


FROM  ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} TD,
AGG_DOMAIN_CPU_DETAIL_1H FLOW  WHERE TD.id = FLOW.DOMAIN_ID AND TIME BETWEEN ${startTime} AND ${endTime}

    AND FLOW.HOST_POOL_ID =${hostPoolId}


    AND FLOW.CLUSTER_ID =${clusterId}


    AND FLOW.HOST_ID =${hostId}


    AND FLOW.OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY FLOW.DOMAIN_ID


        ORDER BY avgCpuRate DESC


        ORDER BY avgMemRate DESC



    LIMIT ${limit}

SELECT DOMAIN_ID as domainId, round(avgMerge(CPU_RATE_AVG),2) as avgCpuRate , maxMerge(CPU_RATE_MAX) as maxCpuRate, minMerge(CPU_RATE_MIN) as minCpuRate, round(avgMerge(MEMORY_AVG),2) as avgMemRate , maxMerge(MEMORY_MAX) as maxMemRate, minMerge(MEMORY_MIN) as minMemRate FROM AGG_DOMAIN_CPU_DETAIL_1H detail WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND DOMAIN_ID = ${domainId}
AND DOMAIN_ID in (${vmIds})
GROUP BY DOMAIN_ID
